import sys

def read_int():
    return int(sys.stdin.readline().strip())

def read_str():
    return sys.stdin.readline().strip()

def read_strs():
    return sys.stdin.readline().strip().split()

def read_ints():
    return list(map(int, sys.stdin.readline().strip().split()))

def read_floats():
    return list(map(float, sys.stdin.readline().strip().split()))

def read_list(size, func=int):
    return [func(x) for x in sys.stdin.readline().strip().split()]

def main():
    n = read_int()
    prices = []
    vitamins = []
    for _ in range(n):
        price, v = read_strs()
        prices.append(int(price))
        vitamins.append(v)

    # find the minimum price of each vitamin
    min_price = [float('inf')] * 3
    for i in range(n):
        for v in vitamins[i]:
            min_price[ord(v) - ord('A')] = min(min_price[ord(v) - ord('A')], prices[i])

    # if there is no minimum price for all three vitamins, return -1
    if any(p == float('inf') for p in min_price):
        print(-1)
    else:
        print(sum(min_price))

if __name__ == '__main__':
    main()
